import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"南堂（宣武门天主堂）","description":"","frontmatter":{},"headers":[],"relativePath":"religion/nantang.md","filePath":"religion/nantang.md","lastUpdated":1784712887000}'),n={name:"religion/nantang.md"};function i(o,t,d,s,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="南堂-宣武门天主堂" tabindex="-1">南堂（宣武门天主堂） <a class="header-anchor" href="#南堂-宣武门天主堂" aria-label="Permalink to &quot;南堂（宣武门天主堂）&quot;">​</a></h1><blockquote><p>&quot;北京四大天主教堂之首，见证中西文化交流四百年。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>南堂，又称宣武门天主堂、圣母无染原罪堂，是北京历史最悠久的天主教堂，始建于明万历三十三年（1605年），距今已有400余年历史。它是北京四大天主教堂（南堂、北堂、东堂、西堂）之首，也是中西文化交流的重要见证。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">6:00-20:00</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">免费</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">30分钟-1小时</td></tr><tr><td style="text-align:left;"><strong>弥撒时间</strong></td><td style="text-align:left;">平日6:30，周日6:30、8:00、10:00、18:00</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁2号线宣武门站B1口</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市西城区前门西大街141号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="始建" tabindex="-1">始建 <a class="header-anchor" href="#始建" aria-label="Permalink to &quot;始建&quot;">​</a></h3><p>明万历三十三年（1605年），意大利传教士利玛窦在北京购得一处住宅，改建成礼拜堂，这就是南堂的雏形。利玛窦是第一位获准在北京长期居住的西方传教士。</p><h3 id="清代重建" tabindex="-1">清代重建 <a class="header-anchor" href="#清代重建" aria-label="Permalink to &quot;清代重建&quot;">​</a></h3><p>清顺治七年（1650年），德国传教士汤若望在利玛窦所建礼拜堂的基础上，主持扩建了一座巴洛克风格的大教堂。汤若望是顺治皇帝的恩师，南堂因此获得朝廷大力支持。</p><h3 id="劫难与重建" tabindex="-1">劫难与重建 <a class="header-anchor" href="#劫难与重建" aria-label="Permalink to &quot;劫难与重建&quot;">​</a></h3><ul><li><strong>康熙年间</strong>：南堂因历法之争一度被查封，后恢复</li><li><strong>乾隆四十年（1775年）</strong>：毁于火灾，后重建</li><li><strong>光绪二十六年（1900年）</strong>：义和团运动中被焚毁</li><li><strong>光绪三十年（1904年）</strong>：重建为今日所见之堂</li></ul><h3 id="近代发展" tabindex="-1">近代发展 <a class="header-anchor" href="#近代发展" aria-label="Permalink to &quot;近代发展&quot;">​</a></h3><p>1958年，南堂成为北京市天主教爱国会所在地。1979年，在改革开放后率先重新开放，是北京恢复宗教活动最早的天主教堂。</p><h2 id="建筑特色" tabindex="-1">建筑特色 <a class="header-anchor" href="#建筑特色" aria-label="Permalink to &quot;建筑特色&quot;">​</a></h2><h3 id="建筑风格" tabindex="-1">建筑风格 <a class="header-anchor" href="#建筑风格" aria-label="Permalink to &quot;建筑风格&quot;">​</a></h3><p>南堂采用巴洛克式建筑风格，同时融入中国传统建筑元素。堂身坐北朝南，平面呈长方形。</p><h3 id="外观特征" tabindex="-1">外观特征 <a class="header-anchor" href="#外观特征" aria-label="Permalink to &quot;外观特征&quot;">​</a></h3><ul><li><strong>立面</strong>：简洁的巴洛克风格，中央为拱形大门</li><li><strong>钟楼</strong>：两侧各有一座钟楼，顶部为中式亭阁造型</li><li><strong>十字架</strong>：钟楼顶端立有十字架</li><li><strong>匾额</strong>：门楣上书&quot;万有真原&quot;四字，为康熙皇帝御笔</li></ul><h3 id="内部结构" tabindex="-1">内部结构 <a class="header-anchor" href="#内部结构" aria-label="Permalink to &quot;内部结构&quot;">​</a></h3><ul><li><strong>面积</strong>：约500平方米，可容纳500余人</li><li><strong>祭台</strong>：主祭台供奉圣母无染原罪像</li><li><strong>彩窗</strong>：彩色玻璃窗描绘圣经故事</li><li><strong>圣像</strong>：两侧墙壁有耶稣苦路像</li></ul><h3 id="康熙御笔" tabindex="-1">康熙御笔 <a class="header-anchor" href="#康熙御笔" aria-label="Permalink to &quot;康熙御笔&quot;">​</a></h3><p>堂内保存有康熙皇帝题写的「万有真原」匾额，以及多幅楹联，是中西文化交流的珍贵遗存。</p><h2 id="文化意义" tabindex="-1">文化意义 <a class="header-anchor" href="#文化意义" aria-label="Permalink to &quot;文化意义&quot;">​</a></h2><h3 id="利玛窦与南堂" tabindex="-1">利玛窦与南堂 <a class="header-anchor" href="#利玛窦与南堂" aria-label="Permalink to &quot;利玛窦与南堂&quot;">​</a></h3><p>利玛窦（Matteo Ricci，1552-1610）是意大利耶稣会传教士，被誉为&quot;西学东渐第一人&quot;。他于1601年抵达北京，1605年建立南堂。利玛窦不仅传播天主教，还将西方科学知识传入中国，同时向欧洲介绍中国文化。</p><h3 id="汤若望与康熙" tabindex="-1">汤若望与康熙 <a class="header-anchor" href="#汤若望与康熙" aria-label="Permalink to &quot;汤若望与康熙&quot;">​</a></h3><p>德国传教士汤若望（Johann Adam Schall von Bell，1591-1666）是南堂的第二任主持人。他曾任钦天监监正，负责编纂历法，深受顺治皇帝信任。康熙幼年曾跟随汤若望学习西方科学知识。</p><h3 id="中西合璧的典范" tabindex="-1">中西合璧的典范 <a class="header-anchor" href="#中西合璧的典范" aria-label="Permalink to &quot;中西合璧的典范&quot;">​</a></h3><p>南堂的建设和重建，体现了中西文化的交融。西方传教士带来欧洲建筑技术和艺术风格，同时也吸收中国建筑元素，形成独特的中西合璧风格。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="参观建议" tabindex="-1">参观建议 <a class="header-anchor" href="#参观建议" aria-label="Permalink to &quot;参观建议&quot;">​</a></h3><ol><li><strong>弥撒时间</strong>：如想体验弥撒仪式，注意弥撒时间（周日场次较多）</li><li><strong>保持安静</strong>：教堂内请保持肃静，尊重宗教礼仪</li><li><strong>着装要求</strong>：避免穿短裤、背心等过于暴露的服装</li><li><strong>拍照注意</strong>：弥撒期间禁止拍照，平时拍照请勿使用闪光灯</li></ol><h3 id="周边游览" tabindex="-1">周边游览 <a class="header-anchor" href="#周边游览" aria-label="Permalink to &quot;周边游览&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">宣武门</td><td style="text-align:center;">步行5分钟</td><td style="text-align:left;">老北京城门遗址</td></tr><tr><td style="text-align:left;">西单</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">繁华商业区</td></tr><tr><td style="text-align:left;">前门大街</td><td style="text-align:center;">步行20分钟</td><td style="text-align:left;">老北京商业街</td></tr><tr><td style="text-align:left;">国家大剧院</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">现代建筑地标</td></tr></tbody></table><h2 id="交通指南" tabindex="-1">交通指南 <a class="header-anchor" href="#交通指南" aria-label="Permalink to &quot;交通指南&quot;">​</a></h2><ul><li><strong>地铁</strong>：2号线宣武门站B1口出站即到</li><li><strong>公交</strong>：宣武门西站，多条线路可达</li><li><strong>步行</strong>：从天安门广场向西步行约20分钟</li></ul><h2 id="四大天主教堂" tabindex="-1">四大天主教堂 <a class="header-anchor" href="#四大天主教堂" aria-label="Permalink to &quot;四大天主教堂&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">名称</th><th style="text-align:left;">别称</th><th style="text-align:left;">位置</th><th style="text-align:center;">始建年代</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>南堂</strong></td><td style="text-align:left;">宣武门教堂</td><td style="text-align:left;">宣武门</td><td style="text-align:center;">1605年</td><td style="text-align:left;">北京最古老天主教堂</td></tr><tr><td style="text-align:left;"><strong>北堂</strong></td><td style="text-align:left;">西什库教堂</td><td style="text-align:left;">西什库</td><td style="text-align:center;">1703年</td><td style="text-align:left;">哥特式建筑</td></tr><tr><td style="text-align:left;"><strong>东堂</strong></td><td style="text-align:left;">王府井教堂</td><td style="text-align:left;">王府井</td><td style="text-align:center;">1655年</td><td style="text-align:left;">罗马式建筑</td></tr><tr><td style="text-align:left;"><strong>西堂</strong></td><td style="text-align:left;">西直门教堂</td><td style="text-align:left;">西直门</td><td style="text-align:center;">1723年</td><td style="text-align:left;">意大利风格</td></tr></tbody></table><p>南堂作为四大教堂之首，是了解北京天主教历史和中西文化交流的最佳起点。</p><hr><p><strong>📍 地址</strong>：北京市西城区前门西大街141号 <strong>📞 电话</strong>：010-66026323 <strong>🌐 弥撒时间</strong>：周日6:30、8:00、10:00、18:00</p>',43)])])}const c=e(n,[["render",i]]);export{f as __pageData,c as default};
